import React, { useEffect, useRef, useState } from 'react';
import logo from '../assets/logo.png';
import './Letter.css';

export default function Letter() {
  const ref = useRef(null);
  const [progress, setProgress] = useState(0);

  useEffect(() => {
    const el = ref.current;
    if (!el) return;
    const onScroll = () => {
      const rect = el.getBoundingClientRect();
      const windowH = window.innerHeight;
      // progress 0→1 as the section scrolls through viewport
      const p = Math.min(1, Math.max(0, (windowH - rect.top) / (windowH + rect.height)));
      setProgress(p);
    };
    window.addEventListener('scroll', onScroll, { passive: true });
    return () => window.removeEventListener('scroll', onScroll);
  }, []);

  return (
    <section id="letter" className="letter-section" ref={ref}>
      <div className="inner">
        <span className="section-label reveal">Candidate Biography</span>
        <h2 className="section-title reveal d1">My Letter To You</h2>

        <div className="letter-card reveal d2">
          {/* Decorative quote mark */}
          <span className="letter-quote-mark">"</span>

          <div className="letter-body">
            <p>Hello All!</p>

            <p>
              I'm Shannon Lo and I'm running for Associated Student Board of Directors as your
              Vice President. I believe what the Board does should directly reflect what students
              need most — from campus resources and Student Organizations, to research
              opportunities and community support.
            </p>

            <p>
              As Vice President, I'll ensure our board's agendas and priorities reflect SJSU
              students' real needs, giving you a meaningful voice in how our community is shaped
              and governed. I've seen firsthand how strong student leadership transforms campus
              life, from academic support to protecting the multicultural centers that make SJSU
              feel like home. Every student pays tuition; every student deserves a seat at
              the table.
            </p>

            <p>
              The responsibility of Vice President is to report on and advocate for faculty
              retention, tenure, and promotion policies — because who teaches you and how
              they're supported directly shapes the quality of your education. I'm committed
              to amplifying voices that are often overlooked, particularly the interests of
              students who have been, and continue to be, marginalized or low income.
            </p>

            <p>
              My approach is straightforward: I'll thoroughly review every proposal, listen
              to what students actually need, and work to drive initiatives that improve
              everyday life for you. Whether it's expanding health &amp; wellness services,
              supporting student organizations, or funding innovation and research — the
              decision should always center SJSU student voices.
            </p>

            <p>
              SJSU's community represents an incredible diversity of backgrounds &amp;
              perspectives. Our leadership should reflect that richness. I am running to
              bring transparency &amp; accessibility, prioritizing student-driven change
              over institutional agendas.
            </p>

            <p>Trust that I will fight for you &amp; be your voice for positive change.</p>

            <p className="letter-sig">
              Sincerely,<br />
              <span>Shannon Yu Hsin Lo</span>
            </p>
          </div>

          {/* Scroll progress bar inside card */}
          <div
            className="letter-progress-bar"
            style={{ width: `${progress * 100}%` }}
          />
        </div>
      </div>
    </section>
  );
}
